        slug = "consigue-blasones-del-alba-de-heroe-para-mejorar-tu-equipo-gracias-a-los-lugares-del-ritua",
        title = "Consigue blasones del alba de heroe para mejorar tu equipo gracias a los Lugares del Ritual",
        excerpt = "Tanto si acabas de subir justo al máximo nivel con uno de tus personajes o necesitas blasones del alba de héroe para mejorar tu equipo, los Lugares del Ritual se han convertido en una actividad que nos proporcionará una muy buena cantidad de estos blasones par",
        author = "AlterTime",
