        id = "0d7510fa5ace",
        slug = "la-comunidad-anuncia-un-nuevo-evento-en-reddit-para-comenzar-de-nuevo-la-temporada-de-desc",
        title = "La comunidad anuncia un nuevo evento en Reddit para comenzar de nuevo la Temporada de Descubrimiento (SoD)",
        excerpt = "La Temporada de Descubrimiento llegó a World of Warcraft como una nueva experiencia para los jugadores basada en la version original del juego. Muchos jugadores disfrutaron esta experiencia y esperan con ganas que Blizzard anuncie una nueva versión de este mod",
        author = "AlterTime",
        publishedAt = 1778229560,
        categories = { "Classic" },
        url = "https://altertime.es/article/la-comunidad-anuncia-un-nuevo-evento-en-reddit-para-comenzar-de-nuevo-la-temporada-de-descubrimiento-so-d",
        cover = "Interface\\AddOns\\AltertimeAddon\\Media\\Covers\\la-comunidad-anuncia-un-nuevo-evento-en-reddit-para-comenzar-de-nuevo-la-temporada-de-desc_01_9fb37c33.tga",
        body = {
            { type = "paragraph", text = "La Temporada de Descubrimiento llegó a World of Warcraft como una nueva experiencia para los jugadores basada en la version original del juego. Muchos jugadores disfrutaron esta experiencia y esperan con ganas que Blizzard anuncie una nueva versión de este modo de juego conocido como Classic+. Hace unos dias, un usuario de reddit llamado Little-Instance abrió un hilo en el que invitaba a todos aquellos jugadores que quisieran apuntarse a revivir de nuevo la experiencia de la Temporada de Descubrimiento en los servidores de América. Según cuenta el creador del hilo, ha conseguido reunir a mas de 200 personas para la Horda y otras 200 para la Alianza. La idea del evento es actuar como si el servidor acabara de abrirse desde cero y que todo el mundo comience con sus personajes hasta conseguir progresar por todo el contenido que ofrece este modo de juego." },
            { type = "paragraph", text = "12/5/2026" },
            { type = "heading", text = "Tyrande/Colinas Pardas/Los Errantes" },
            { type = "bullet", text = "Fetiche de Sen'jin" },
            { type = "bullet", text = "Celada Rompeterra" },
            { type = "image", path = "Interface\\AddOns\\AltertimeAddon\\Media\\Inline\\la-comunidad-anuncia-un-nuevo-evento-en-reddit-para-comenzar-de-nuevo-la-temporada-de-desc_02_a3b72fff.tga", width = 760, height = 427 },
        },
